public class MaandTotaalVormer {

    private final MaandTotaalService maandTotaalService;
    private ArtikelLoonElementManagerFactory artikelLoonElementManagerFactory;
    private ArtikelMotorDataManagerFactory artikelMotorDataManagerFactory;
    private ArtikelManager artikelManager;
    private ControleAgendaService controleAgendaService;
    private ResultaatHandler handler;
    private AardKodeExtensieFacade aardKodeExtensieFacade;
    private ConstantService constantService;

    public MaandTotaalVormer(
            MaandTotaalService maandTotaalService, ArtikelLoonElementManagerFactory artikelLoonElementManagerFactory,
            ArtikelMotorDataManagerFactory artikelMotorDataManagerFactory, ArtikelManager artikelManager, ControleAgendaService controleAgendaService,
            ResultaatHandler handler, NlpGlobalService nlpGlobalService) {
        this.maandTotaalService = maandTotaalService;
        this.artikelLoonElementManagerFactory = artikelLoonElementManagerFactory;
        this.artikelMotorDataManagerFactory = artikelMotorDataManagerFactory;
        this.artikelManager = artikelManager;
        this.controleAgendaService = controleAgendaService;
        this.handler = handler;
        this.aardKodeExtensieFacade = nlpGlobalService.getAardKodeExtensieFacade();
        this.constantService = nlpGlobalService.getConstantService();
    }

    public MaandTotaalVormer(MaandTotaalService maandTotaalService) {
        this.maandTotaalService = maandTotaalService;
    }

    public void vorm(
            Admin admin, Persoon persoon, Set<Opdracht> opdrachten, RekenTijd rekenTijd, RegulManager regulManager, RekenFeedback feedback, String actor,
            OpslaanNulResultaten saveNulResultaten) {
        ConstantManager constantManager = new ConstantManagerImp(admin, constantService);
        Constant afwijkendeVrwPerMaandCst = constantManager.getActualConstant(Konstanten.CST_HVZ_AFWIJKENDE_VERW_PER_MAAND, rekenTijd);
        boolean afwijkendeVrwPerMaand = afwijkendeVrwPerMaandCst.getBoolean();
        List<MaandTotaal1> gelockten = findBestaandeMaandTotalen(admin, persoon, rekenTijd, afwijkendeVrwPerMaand);

        MaandTotaalBeheer rekenResultatenBeheer = new MaandTotaalBeheer();
        List<RekenHoofd> rekenResultaten =
                artikelMotorDataManagerFactory.findBestaandeRekenResultatenKwartaal(admin, persoon.getId(), rekenTijd, artikelManager);
        Set<Integer> opdrachtIds = opdrachten.stream().map(Opdracht::getId).collect(Collectors.toSet());
        rekenResultaten = rekenResultaten.stream().filter(x -> opdrachtIds.contains(x.getOpdracht().getId())).collect(Collectors.toList());
        ArtikelLoonElementManager manager = artikelLoonElementManagerFactory.create(persoon, opdrachten, rekenResultaten);
        Map<Integer, LocalDateInterval> opdrachtIdToMaandTotaalPeriode =
                bepaalMaandTotaalPeriode(admin, rekenTijd, persoon, opdrachten, gelockten, afwijkendeVrwPerMaand);

        ListMultimap<IdDatumKey, NlpPrestatie> opdrachtIdToPrestatiesMap =
                artikelMotorDataManagerFactory.getOpdrachtIdToPrestatiesMap(admin, persoon, rekenTijd);

        LoonCodeManager loonCodeManager = new LoonCodeManagerImp(regulManager, aardKodeExtensieFacade);
        List<MaandTotaal1> outputs = rekenResultatenBeheer
                .maakMaandTotaal(opdrachten, rekenTijd, manager, gelockten, opdrachtIdToMaandTotaalPeriode, opdrachtIdToPrestatiesMap, saveNulResultaten, loonCodeManager,
                        constantManager);
        checkRegulMaandtotalen(persoon, outputs, regulManager);

        persisteerMaandtotalen(admin, outputs, feedback);
        controleZwevendeMaandtotalen(admin, persoon, opdrachten, rekenTijd, regulManager, feedback, outputs, rekenResultaten, actor);
    }

    private void controleZwevendeMaandtotalen(
            Admin admin, Persoon persoon, Set<Opdracht> opdrachten, RekenTijd rekenTijd, RegulManager regulManager, RekenFeedback feedback,
            List<MaandTotaal1> outputs, List<RekenHoofd> rekenResultaten, String actor) {
        boolean openResult = rekenResultaten.stream().flatMap(x -> x.getArtikelHoofden().stream()).anyMatch(x -> x.getSnummer() == null);
        boolean enkelOverdracht = rekenResultaten.stream().anyMatch(x -> x.getRekenLijnen().isEmpty() && !x.getRekenOverdrachten().isEmpty());
        if ((feedback.getAantalArtikelHoofden() == 0 && !openResult && !enkelOverdracht) && feedback.getAantalMaandtotalen() > 0) {
            Set<Integer> opdrachtNrs = outputs.stream().filter(x -> x.getId() != null).filter(this::isNietMaandtotaalEnkelTenGevolgeVanLoonCodeEnkelInRekenElement)
                    .map(MaandTotaal1::getOpdrachtNummer).collect(Collectors.toSet());
            for (Integer opdrachtNr : opdrachtNrs) {
                Opdracht opdracht = RekenTools.findByOpdrachtNr(opdrachten, opdrachtNr);
                ControlesRekenResultaten controles = new ControlesRekenResultaten(null, null);
                List<ControleAgenda> bestaandeControles = controleAgendaService
                        .findOpenControles(admin, rekenTijd.rekenPeriode, persoon.getId(), Sets.newHashSet(opdracht.getOpdrachtnr()),
                                RekenControleCode.ZWEVEND_MAANDTOTAAL);
                if (bestaandeControles.isEmpty()) {
                    ControleAgenda punt = controles.maakControleAgenda(RekenControleCode.ZWEVEND_MAANDTOTAAL, opdracht, rekenTijd.beginDatum,
                            "Er zijn maandtotalen zonder artikelhoofd", actor);
                    Integer rekenBatchNr = handler.getRekenBatchNr();
                    if (rekenBatchNr != null) {
                        punt.setRekenBatchNr(rekenBatchNr);
                    }
                    controleAgendaService.create(admin, punt);
                    regulManager.addWaarschuwing(punt);
                }
                int aantal = feedback.getAantalControleAgendas();
                feedback.setAantalControleAgendas(aantal + 1);
            }
        }
    }

    private static final Set<CodeExtensie> LOONCODES_ENKEL_IN_REKENELEMENTEN =
            ImmutableSet.of(CodeExtensie.ANTWERPEN_2DE_PENSIOENPIJLER_ONDER_GRENS, CodeExtensie.ANTWERPEN_2DE_PENSIOENPIJLER_BOVEN_GRENS);

    private boolean isNietMaandtotaalEnkelTenGevolgeVanLoonCodeEnkelInRekenElement(MaandTotaal1 maandTotaal1) {
        boolean zeroMaandtotaal = maandTotaal1.isZeroMaandtotaal();
        boolean enkelUizondering = !maandTotaal1.getRekenElementen().isEmpty() &&
                maandTotaal1.getRekenElementen().stream().allMatch(x -> LoonCodeTools.matches(x, LOONCODES_ENKEL_IN_REKENELEMENTEN));
        return !(zeroMaandtotaal && enkelUizondering);
    }

    protected void persisteerMaandtotalen(Admin admin, List<MaandTotaal1> outputs, RekenFeedback feedback) {
        //Bij het persisteren van mt ontkoppellen we de rekenelementen voor hibernate technische redenen.
        //We houden ze hier bij om ze erna terug te koppelen aan de mts voor gebruik in een latere controle
        List<RekenElement> rekenElementen = outputs.stream().map(MaandTotaal1::getRekenElementen).flatMap(Collection::stream).collect(Collectors.toList());
        TimeLogContext.getInstance().startTimeLogging("MaandtotaalResultaatHandlerImp.maandTotaalService.create");
        maandTotaalService.create(admin, outputs);
        TimeLogContext.getInstance().endTimeLogging();
        SetMultimap<Integer, RekenElement> idToRekenElement =
                rekenElementen.stream().collect(Multimaps.toMultimap(x -> x.getMaandTotaal1().getId(), x -> x, HashMultimap::create));
        outputs.forEach(x -> x.setRekenElementen(idToRekenElement.get(x.getId())));
        if (feedback != null) {
            int count = (int) outputs.stream().filter(x -> x.getId() != null).count();
            feedback.setAantalMaandtotalen(count);
        }
    }

    public void cleanMaandtotalen(Admin admin, RekenTijd rekenTijd, Persoon persoon) {
        TimeLogContext.getInstance().startTimeLogging("MaandtotaalResultaatHandlerImp.maandTotaalService.delete");
        maandTotaalService.deleteZonderSnummer(admin, persoon, rekenTijd.rekenPeriode);
        TimeLogContext.getInstance().endTimeLogging();
    }

    public List<MaandTotaal1> findBestaandeMaandTotalen(Admin admin, Persoon persoon, RekenTijd rekenTijd, boolean afwijkendeVrwPerMaand) {
        List<MaandTotaal1> gelockten = findBestaandeMaandTotalenAlgemeen(admin, persoon, rekenTijd.rekenPeriode, AardMaandtotaal.MAAND, afwijkendeVrwPerMaand);
        gelockten.addAll(findBestaandeMaandTotalenAlgemeen(admin, persoon, rekenTijd.rekenPeriode, AardMaandtotaal.KWARTAAL, afwijkendeVrwPerMaand));
        gelockten.addAll(findBestaandeMaandTotalenAlgemeen(admin, persoon, rekenTijd.rekenPeriode, AardMaandtotaal.AST_PRE_OMSCH, afwijkendeVrwPerMaand));
        return gelockten;
    }

    protected List<MaandTotaal1> findBestaandeMaandTotalenAlgemeen(
            Admin admin, Persoon persoon, LocalDateInterval periode, AardMaandtotaal type, boolean afwijkendeVrwPerMaand) {
        Function<Object, Criterium> excludeInclude;

        if (typeIsKwartaal(type, afwijkendeVrwPerMaand)) {
            periode = new Quarter(periode.getStart());
            excludeInclude = Criterium::IN;
        } else {
            excludeInclude = Criterium::EX;
        }
        CriteriaBuilder cb = new CriteriaBuilder();
        if (type == AardMaandtotaal.AST_PRE_OMSCH) {
            cb.and("eindDatum", Criterium.EQ(periode.getEnd()));
        } else {
            cb.and("beginDatum", Criterium.EQ(periode.getStart()));
        }
        cb.and("persoon.id", Criterium.EQ(persoon.getId()));
        cb.and("snummer", Criterium.NOT(0));
        if (type != AardMaandtotaal.AST_PRE_OMSCH && !afwijkendeVrwPerMaand) {
            cb.and("hoedanigheid", excludeInclude.apply(RekenTools.codeEnumListToCodeList(RekenTools.HOEDANIGHEDEN_KWARTAAL_MAANDTOTAAL)));
        }
        cb.and("aardCode", Criterium.EQ(type.getCode()));
        cb.fetch("rekenElementen,maandTotaal2,maandTotaal3,inhoudingen");
        return maandTotaalService.findByCriteria(admin, cb);
    }

    private boolean typeIsKwartaal(AardMaandtotaal type, boolean afwijkendeVrwPerMaand) {
        return type == AardMaandtotaal.KWARTAAL && !afwijkendeVrwPerMaand;
    }

    private Map<Integer, LocalDateInterval> bepaalMaandTotaalPeriode(
            Admin admin, RekenTijd rekenTijd, Persoon persoon, Set<Opdracht> opdrachten, List<MaandTotaal1> gelockten, boolean afwijkendeVerwerkingPerMaand) {
        Map<Integer, LocalDateInterval> map = new HashMap<>();
        LocalDateInterval apoRefPeriode = rekenTijd.rekenPeriode;
        if (rekenTijd.isApo) {
            List<ApoHoofd> apoHoofden = artikelMotorDataManagerFactory.findApoInput(admin, rekenTijd, persoon);
            apoRefPeriode = voegApoHoofdenTijdsIntervallentoe(rekenTijd, map, apoRefPeriode, apoHoofden);
            if (apoHoofden.isEmpty() && !gelockten.isEmpty()) {
                voegPersoonsOpdrachtTijdsIntervallenToe(rekenTijd, persoon, gelockten, map);
            }
        }
        for (Opdracht opdracht : opdrachten) {
            Integer opdrachtId = opdracht.getId();
            if (rekenTijd.isApo) {
                LocalDateInterval finalApoRefPeriode = apoRefPeriode;
                map.computeIfAbsent(opdrachtId, x -> finalApoRefPeriode);
            } else if (RekenTools.isOpdrachtMetKwartaalMaandtotalen(opdracht.getHoedanigheid()) && !afwijkendeVerwerkingPerMaand) {
                map.put(opdrachtId, new Quarter(rekenTijd.beginDatum));
            } else {
                map.put(opdrachtId, rekenTijd.rekenPeriode);
            }
        }
        return map;
    }

    private void voegPersoonsOpdrachtTijdsIntervallenToe(RekenTijd rekenTijd, Persoon persoon, List<MaandTotaal1> gelockten, Map<Integer, LocalDateInterval> map) {
        Map<Integer, Opdracht> opdrachtnrToOpdracht = persoon.getOpdrachten().stream().collect(Collectors.toMap(Opdracht::getOpdrachtnr, Function.identity()));
        for (MaandTotaal1 maandTotaal1 : gelockten) {
            Integer opdrachtId = opdrachtnrToOpdracht.get(maandTotaal1.getOpdrachtNummer()).getId();
            LocalDateInterval periode = map.get(opdrachtId);
            LocalDateInterval huidigePeriode = new LocalDateInterval(maandTotaal1.getBeginDatum(), maandTotaal1.getEindDatum());
            if (periode == null) {
                map.put(opdrachtId, huidigePeriode);
            } else if (!periode.equals(huidigePeriode)) {
                map.put(opdrachtId, rekenTijd.rekenPeriode);
            }
        }
    }

    private LocalDateInterval voegApoHoofdenTijdsIntervallentoe(
            RekenTijd rekenTijd, Map<Integer, LocalDateInterval> map, LocalDateInterval apoRefPeriode, List<ApoHoofd> apoHoofden) {
        for (ApoHoofd apoHoofd : apoHoofden) {
            Integer opdrachtId = apoHoofd.getOpdracht().getId();
            LocalDateInterval periode = map.get(opdrachtId);
            LocalDateInterval huidigePeriode = new LocalDateInterval(apoHoofd.getBeginDatum(), apoHoofd.getEindDatum());
            if (periode == null) {
                map.put(opdrachtId, huidigePeriode);
                apoRefPeriode = huidigePeriode;
            } else if (!periode.equals(huidigePeriode)) {
                map.put(opdrachtId, rekenTijd.rekenPeriode);
            }
        }
        return apoRefPeriode;
    }

    private void checkRegulMaandtotalen(Persoon persoon, List<MaandTotaal1> outputs, RegulManager regulManager) {
        Map<Integer, Opdracht> opdrachtNrToOpdrachtMap = maakOpdrachtNrToOpdrachtMap(persoon);
        for (MaandTotaal1 maandTotaal1 : outputs) {
            Opdracht opdracht = opdrachtNrToOpdrachtMap.get(maandTotaal1.getOpdrachtNummer());
            AkeTijdperk huidigTijdperk = RekenTools.getTijdperk(maandTotaal1.getBeginDatum());
            WerkgeversCategorie werkgeversCategorie = WerkgeversCategorie.getByCode(maandTotaal1.getWerkgeversCategorie());
            DmfapplWnkengetal werknemersKengetal = DmfapplWnkengetal.getByCode(maandTotaal1.getWerknemersKengetal());
            if (huidigTijdperk == AkeTijdperk.RSZPPO && !(werkgeversCategorie == WerkgeversCategorie.NVT
                    && werknemersKengetal == DmfapplWnkengetal.NVT)) {
                regulManager.doRegulException(opdracht, Regulkode.DMFAPPL_VOOR_2005);
            }
            for (RekenElement rekenElement : maandTotaal1.getRekenElementen()) {
                AkeTijdperk tijdperk = AkeTijdperk.getByCode(rekenElement.getTijdperk());
                AardKodeExt aard = AardKodeExt.getByCode(rekenElement.getAard());
                if ((RekenTools.AARD_MET_TP_BEIDE.contains(aard) && tijdperk != AkeTijdperk.BEIDE) || (
                        RekenTools.AARD_MET_TIJDAFHANKELIJKE_TP.contains(aard) && huidigTijdperk != tijdperk)) {
                    regulManager.doRegulException(opdracht, Regulkode.TP_ONGELDIG);
                }
            }
        }
    }

    private Map<Integer, Opdracht> maakOpdrachtNrToOpdrachtMap(Persoon persoon) {
        Map<Integer, Opdracht> map = new HashMap<>();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            map.put(opdracht.getOpdrachtnr(), opdracht);
        }
        return map;
    }
}
